# Writing to a file
try:
    with open("example.txt", "w") as f:
        f.write("Hello, file!\n")
        f.write("This is the second line.\n")
    print("File 'example.txt' created successfully.")
except IOError as e:
    print(f"Error writing to file: {e}")

# Reading from a file
try:
    with open("example.txt", "r") as f:
        print("\nContents of 'example.txt':")
        for line in f:
            print(line.strip())
except FileNotFoundError:
    print("Error: File not found.")
except IOError as e:
    print(f"Error reading file: {e}")

# Make sure to install the library first: pip install Flask
from flask import Flask, jsonify

# Create a Flask web server
app = Flask(__name__)

# Define a route for the root URL ('/')
@app.route('/')
def home():
    return "<h1>Welcome to the Flask API!</h1><p>Try the /api/data endpoint.</p>"

# Define a route that returns JSON data
@app.route('/api/data')
def get_data():
    sample_data = {
        'id': 1,
        'name': 'Sample Item',
        'values': [10, 20, 30]
    }
    return jsonify(sample_data)

# Run the app if the script is executed directly
if __name__ == '__main__':
    # To run: flask --app your_script_name run
    # Or in debug mode: python your_script_name.py
    app.run(debug=True)
